import importlib.util, math; spec = importlib.util.spec_from_file_location('m', '/tmp/eval_kv/kv_cache.py'); mod = importlib.util.module_from_spec(spec); spec.loader.exec_module(mod); cache = mod.KVCache(); steps_K = [[1.0, 0.0], [0.0, 1.0], [1.0, 1.0]]; steps_V = [[10.0, 0.0], [0.0, 20.0], [5.0, 5.0]]; queries = [[1.0, 0.0], [0.0, 1.0], [0.5, 0.5]]; results = []; 
for K, V, Q in zip(steps_K, steps_V, queries):
    cache.append(K, V); results.append(cache.attend(Q))
import math as _m
def ref(Qs, Ks, Vs):
    out=[]
    for q in Qs:
        scores=[sum(qi*ki for qi,ki in zip(q,k))/_m.sqrt(len(q)) for k in Ks]
        m=max(scores); ex=[_m.exp(s-m) for s in scores]; Z=sum(ex); w=[e/Z for e in ex]
        d_v=len(Vs[0]); out.append([sum(w[i]*Vs[i][j] for i in range(len(w))) for j in range(d_v)])
    return out
for t in range(3):
    r = ref(queries[:t+1], steps_K[:t+1], steps_V[:t+1])[-1]
    got = results[t]
    assert all(abs(a-b) < 1e-6 for a,b in zip(got, r)), f'step {t}: got {got} expected {r}'
print('OK')
